def topological_sort(graph):
    """
    Perform a topological sort on a directed acyclic graph (DAG).

    :param graph: A dictionary mapping each node to its list of dependencies.
    :return: A valid topological ordering of the nodes in the graph, or None if a cycle is detected.

    Note:
    - If there's a cycle in the graph, it will not be possible to complete the sorting.
    """

    def is_cyclic_util(node, visited, rec_stack):
        visited[node] = True
        rec_stack[node] = True

        # Check for cycles
        if node in graph:
            for neighbour in graph[node]:
                if not visited[neighbour]:
                    if is_cyclic_util(neighbour, visited, rec_stack):
                        return True
                elif rec_stack[neighbour]:
                    return True

        rec_stack[node] = False  # Remove the node from recursion stack
        topological_order.append(node)  # Add to the ordering as the graph becomes acyclic
        return False

    vertices = list(graph.keys())
    visited = {vertex: False for vertex in vertices}
    rec_stack = {vertex: False for vertex in vertices}
    topological_order = []

    for vertex in vertices:
        if not visited[vertex]:
            if is_cyclic_util(vertex, visited, rec_stack):
                return None  # Cycle exists

    return topological_order[::-1]  # Reverse to get correct order
```

