def topological_sort(graph):
    in_degree = {node: 0 for node in graph}

    # Calculate the in-degree of each node.
    for nodes, dependencies in graph.items():
        for dependency in dependencies:
            in_degree[dependency] += 1

    # Initialize queue with all nodes having in-degree of zero
    from collections import deque
    queue = deque([node for node in in_degree if in_degree[node] == 0])
    order = []

    while queue:
        node = queue.popleft()
        order.append(node)

        # Decrease the in-degree of each dependent node by 1.
        for dependency in graph[node]:
            in_degree[dependency] -= 1
            # If any dependent node has an in-degree of zero, add it to the queue.
            if in_degree[dependency] == 0:
                queue.append(dependency)

    # Check if all nodes are visited (i.e., no cycle)
    if len(order) != len(in_degree):
        raise ValueError("Graph contains a cycle; topological sorting is not possible.")

    return order
